async (page) => {
  // 1. Open inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(800);
  // 2. Click the item slot (slot 0 - bronze axe)
  await page.evaluate((idx) => {
    const slots = document.querySelectorAll('.item-slot');
    if (slots[idx]) slots[idx].click();
  }, 0);
  await page.waitForTimeout(800);
  // 3. Click the equip button in the popup
  await page.evaluate(() => {
    const btn = document.querySelector('.action-equip');
    if (btn) btn.click();
  });
  await page.waitForTimeout(500);
  // 4. Close inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(500);
  // Set attack style to Hack (index 0)
  await page.evaluate(() => window.game.player.setAttackStyle(0));
  await page.waitForTimeout(300);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return 'Equipped bronze axe and set Hack attack style';
}

async (page) => {
  // Walk to Programmer NPC (click_x=792, click_y=288)
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, { x: 792, y: 288 });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  return state;
}

async (page) => {
  // Try clicking progressively further south to exit building
  const positions = [
    {x: 640, y: 460},
    {x: 640, y: 490},
    {x: 640, y: 510},
    {x: 640, y: 530}
  ];

  for (const pos of positions) {
    await page.evaluate(({x, y}) => {
      const canvas = document.getElementById('canvas');
      canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, pos);
    await page.waitForTimeout(1500);
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const pos2 = JSON.parse(state).player_position;
    if (pos2.y > 896) {
      return `Moved! Clicked ${JSON.stringify(pos)}, now at ${JSON.stringify(pos2)}`;
    }
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  return JSON.parse(state).player_position;
}

