async (page) => {
  const click = async (sx, sy) => {
    await page.evaluate(({x, y}) => {
      const canvas = document.getElementById('canvas');
      canvas.dispatchEvent(new MouseEvent('mousedown', { clientX: x, clientY: y, bubbles: true, ctrlKey: false, button: 0 }));
      canvas.dispatchEvent(new MouseEvent('mouseup', { clientX: x, clientY: y, bubbles: true, ctrlKey: false, button: 0 }));
      canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false, button: 0 }));
    }, {x: sx, y: sy});
  };

  // Get camera to calculate screen position of tile x=362, y=894
  const camInfo = await page.evaluate(() => {
    const cam = window.game.camera;
    const zoom = 3;
    const playerGridX = window.game.player.gridX;
    const playerGridY = window.game.player.gridY;
    // Target tile x=362, y=894
    const targetTileX = 362, targetTileY = 894;
    // Camera pixel position
    const camPixX = cam.x, camPixY = cam.y;
    // Target pixel position
    const targPixX = targetTileX * 16, targPixY = targetTileY * 16;
    // Screen position
    const scrX = (targPixX - camPixX) * zoom;
    const scrY = (targPixY - camPixY) * zoom;
    return { scrX, scrY, camPixX, camPixY, playerPos: {x: playerGridX, y: playerGridY} };
  });

  // Click at calculated position for x=362, y=894
  await click(Math.round(camInfo.scrX), Math.round(camInfo.scrY));
  await page.waitForTimeout(3000);

  const pos = await page.evaluate(() => {
    const s = window.__latestGameState;
    return s ? s.player_position : null;
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png', timeout: 15000 });
  return JSON.stringify({ camInfo, pos });
}

