async (page) => {
  const click = async (sx, sy) => {
    await page.evaluate(({x, y}) => {
      const canvas = document.getElementById('canvas');
      canvas.dispatchEvent(new MouseEvent('mousedown', { clientX: x, clientY: y, bubbles: true, ctrlKey: false, button: 0 }));
      canvas.dispatchEvent(new MouseEvent('mouseup', { clientX: x, clientY: y, bubbles: true, ctrlKey: false, button: 0 }));
      canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false, button: 0 }));
    }, {x: sx, y: sy});
    await page.waitForTimeout(4000);
    return await page.evaluate(() => window.__latestGameState?.player_position);
  };

  // Calculate screen pos for Secret Agent at grid (137, 171)
  const scrPos = await page.evaluate(() => {
    const cam = window.game.camera;
    const zoom = 3;
    return {
      x: Math.round((137 * 16 - cam.x) * zoom),
      y: Math.round((171 * 16 - cam.y) * zoom)
    };
  });

  // Clamp to screen
  const tx = Math.max(50, Math.min(1230, scrPos.x));
  const ty = Math.max(50, Math.min(670, scrPos.y));

  let pos = await click(tx, ty);
  console.log(`Clicked (${tx},${ty}):`, JSON.stringify(pos));

  // Continue if not there yet
  if (pos && (Math.abs(pos.x - 137) > 5 || Math.abs(pos.y - 171) > 5)) {
    const scrPos2 = await page.evaluate(() => {
      const cam = window.game.camera;
      const zoom = 3;
      return {
        x: Math.round((137 * 16 - cam.x) * zoom),
        y: Math.round((171 * 16 - cam.y) * zoom)
      };
    });
    const tx2 = Math.max(50, Math.min(1230, scrPos2.x));
    const ty2 = Math.max(50, Math.min(670, scrPos2.y));
    pos = await click(tx2, ty2);
    console.log(`Click2 (${tx2},${ty2}):`, JSON.stringify(pos));
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png', timeout: 15000 });
  return JSON.stringify(pos);
}

