async (page) => {
  // Find open tiles and navigate to exit
  const scanResult = await page.evaluate(() => {
    const map = window.game.map;
    const px = window.game.player.gridX, py = window.game.player.gridY;
    const scan = [];
    for (let dy = -10; dy <= 10; dy++) {
      for (let dx = -10; dx <= 10; dx++) {
        const tx = px + dx, ty = py + dy;
        if (!map.isColliding(tx, ty)) {
          scan.push({x: tx, y: ty});
        }
      }
    }
    return { playerPos: {x: px, y: py}, openTiles: scan.slice(0, 10) };
  });

  // Try warp with longer delay
  await page.evaluate(() => window.game.menu.warp.show());
  await page.waitForTimeout(2000);

  const warpVisible = await page.evaluate(() => {
    const el = document.querySelector('[id*="warp"]');
    return el ? { found: true, id: el.id } : { found: false };
  });

  await page.evaluate(() => document.getElementById('warp0')?.click());
  await page.waitForTimeout(4000);

  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png', timeout: 15000 });
  return JSON.stringify({ scanResult, warpVisible, pos });
}

